INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (24, '25', 'İnsanların yeteneklerini keşfeder ve doğru şekilde değerlendirir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (24, '26', 'Görevlerin yerine getirilebilmesi için gerekli olan kaynakları belirler ve organize eder.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (24, '27', 'Aldığı kararların arkasındadır ve bu kararların sorumluluğunu üstlenir. ');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (24, '28', 'Zor durumlarda ve baskı altında en etkili kararı verir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (24, '29', 'Çalışanların gelişimi için öğrenme ortamı yaratır. Ekibini ve kendini sürekli geliştirir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (24, '30', 'Davranışları ile ekibe örnek olur. Söyledikleri ile yaptıkları tutarlıdır.');
INSERT INTO position_categories (id, positionId, name) VALUES (25, 5, 'İş Disiplini ve Tutum');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (25, '31', 'Dış görünüşüne, saçına, sakalına, kişisel hijyenine dikkat eder. Eldiven, bone kullanır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (25, '32', 'Şirketin eğitimlerine aktif olarak katılır, atanmış eğitimlerini tamamlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (25, '33', 'Restoran hedeflerinden haberdardır, hedef için elinden gelen gayreti gösterir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (25, '34', 'Mazeret bildirmeden işe gelmemezlik yapmaz. Vardiya ve mola düzenine uyar.');
INSERT INTO position_categories (id, positionId, name) VALUES (26, 5, 'Ürün Kalitesi ve Standartlara Uyum');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (26, '35', 'Ürünleri reçetelere uygun hazırlar. Ürünlerin her seferinde aynı kalite ve tatta olmasını sağlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (26, '36', 'Et pişirme tekniklerine hakimdir. Şirket standartlarına uygun pişirme yapar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (26, '37', 'Patates kızartma standartlarını bilir, doğru şekilde uygular.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (26, '38', 'Peynir çubukları, soğan halkası, nugget vb. ürünleri doğru sürede uygun sıcaklıkta pişirir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (26, '39', 'Ekmek kesimini ve burger süslemesini standartlara uygun olarak yapar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (26, '40', 'Kızartma yağı TPM ölçümünü doğru olarak yapar.İç ısı standardını sağlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (26, '41', 'Yağ filtre işlemini standartlara uygun olarak yapar. Koruyucu materyalleri kullanır.');
INSERT INTO position_categories (id, positionId, name) VALUES (27, 5, 'Gıda Güvenliği ve Hijyen');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (27, '42', 'Ürünlerin son kullanma tarihine dikkat eder. Zayii olmasına izin vermez. (FIFO-İlk Giren İlk Çıkar)');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (27, '43', 'Sebzeleri standartlara uygun şekilde yıkar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (27, '44', 'Küçük ekipmanların hijyenini standartlara uygun olarak sağlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (27, '45', 'Gıda güvenliği ve operasyonel prosedür ve talimatları bilir, bunlara uygun hareket eder.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (27, '46', 'Temizlik kimyasallarını İSG kurallarına uygun şekilde kullanır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (27, '47', 'Çalışma süresince İSG kurallarına uygun hareket eder.');
INSERT INTO position_categories (id, positionId, name) VALUES (28, 5, 'İstasyon Yönetimi');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (28, '48', 'İstasyonlarda doğru ürün miktarının bulunmasına özen gösterir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (28, '49', 'Çalıştığı istasyonların temizliğini ve düzenini sağlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (28, '50', 'Çalıştığı ekipmanları özenli ve titiz kullanır. Temizliğini yapar.');

